  const [keyDraft, setKeyDraft] = useState("");
  const [ready, setReady] = useState(false); // localStorage read has happened

  const [links, setLinks] = useState<Link[]>([]);
  const [loading, setLoading] = useState(false);
  const [loadError, setLoadError] = useState<string | null>(null);

  const [url, setUrl] = useState("");
  const [ttl, setTtl] = useState("");
  const [saving, setSaving] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);
  const [justCreated, setJustCreated] = useState<Link | null>(null);
  const [copied, setCopied] = useState<string | null>(null);

  const urlRef = useRef<HTMLInputElement>(null);

  // localStorage isn't available during SSR, so the key can only be read after
  // mount. `ready` keeps the first paint from flashing the sign-in prompt at
  // someone who is already signed in.
  useEffect(() => {
    setApiKey(window.localStorage.getItem(KEY_STORAGE));
    setReady(true);
  }, []);

  const loadLinks = useCallback(async (key: string) => {
    setLoading(true);
    try {
      setLinks(await getLinks(key));
      setLoadError(null);
    } catch (e) {
      const message =
        e instanceof ApiError ? e.message : "Couldn't load your links.";
      setLoadError(message);
      // A bad key shouldn't leave a stale list on screen implying it worked.
      if (e instanceof ApiError && e.status === 401) setLinks([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (apiKey) loadLinks(apiKey);
  }, [apiKey, loadLinks]);

  function saveKey(e: React.FormEvent) {
    e.preventDefault();
    const trimmed = keyDraft.trim();
    if (!trimmed) return;
    window.localStorage.setItem(KEY_STORAGE, trimmed);
    setApiKey(trimmed);
    setKeyDraft("");
    setLoadError(null);
  }

  function forgetKey() {
    window.localStorage.removeItem(KEY_STORAGE);
    setApiKey(null);
    setLinks([]);
    setJustCreated(null);
    setLoadError(null);
  }

  async function submit(e: React.FormEvent) {
    e.preventDefault();
    if (!apiKey || !url.trim() || saving) return;

    setSaving(true);
    setFormError(null);
    try {
      const days = ttl.trim() ? Number(ttl) : null;
      const link = await createLink(apiKey, {
        url: url.trim(),
        expires_in_days: days,
      });
      setJustCreated(link);
      setUrl("");
      setTtl("");
      await loadLinks(apiKey);
      urlRef.current?.focus();
    } catch (e) {
      setFormError(
        e instanceof ApiError ? e.message : "Couldn't shorten that URL."
      );
    } finally {
      setSaving(false);
    }
  }

  async function copy(text: string) {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(text);
      setTimeout(() => setCopied((c) => (c === text ? null : c)), 1500);
    } catch {
      setFormError("Couldn't copy to clipboard.");
    }
  }

  if (!ready) return null;

  // --- signed out -----------------------------------------------------------
  if (!apiKey) {
    return (
      <main className={styles.main}>
        <div className={styles.gate}>
          <h1 className={styles.title}>Shortener</h1>
          <p className={styles.lede}>
            Paste an API key to get started. Create one with{" "}
            <code className={styles.code}>python seed_key.py my-laptop</code> in
            the backend folder.
          </p>
          <form onSubmit={saveKey} className={styles.gateForm}>
            <input
              className={styles.input}
              type="password"
              value={keyDraft}
              onChange={(e) => setKeyDraft(e.target.value)}
              placeholder="API key"
              aria-label="API key"
              autoFocus
            />
            <button
              className={styles.primary}
              type="submit"
              disabled={!keyDraft.trim()}
            >
              Continue
            </button>
          </form>
          <p className={styles.note}>
            Stored in this browser only, and sent as the{" "}
            <code className={styles.code}>X-API-Key</code> header.
          </p>
        </div>
      </main>
    );
  }

  // --- signed in ------------------------------------------------------------
  return (
    <main className={styles.main}>
      <header className={styles.header}>
        <h1 className={styles.title}>Shortener</h1>
        <button className={styles.ghost} onClick={forgetKey}>
          Forget key
        </button>
      </header>

      <form onSubmit={submit} className={styles.form}>
        <div className={styles.row}>
          <input
            ref={urlRef}
            className={styles.input}
            value={url}
            onChange={(e) => setUrl(e.target.value)}
            placeholder="https://example.com/a-very-long-url"
            aria-label="URL to shorten"
            autoFocus
          />
          <input
            className={styles.ttl}
            value={ttl}
            onChange={(e) => setTtl(e.target.value)}
            placeholder="Expires (days)"
            aria-label="Expires in days, optional"
            inputMode="numeric"
0          />
          <button
            className={styles.primary}
            type="submit"
            disabled={!url.trim() || saving}
          >
            {saving ? "Shortening…" : "Shorten"}
          </button>
        </div>
        {formError && (
          <p className={styles.error} role="alert">
            {formError}
          </p>
        )}
      </form>

      {justCreated && (
        <div className={styles.result}>
          <a
            className={styles.resultLink}
            href={justCreated.short_url}
            target="_blank"
            rel="noreferrer"
          >
            {justCreated.short_url}
          </a>
          <button
            className={styles.copy}
            onClick={() => copy(justCreated.short_url)}
          >
            {copied === justCreated.short_url ? "Copied" : "Copy"}
          </button>
        </div>
      )}

      <section className={styles.dash}>
        <h2 className={styles.sectionTitle}>Your links</h2>

        {loading && links.length === 0 ? (
          <p className={styles.muted}>Loading…</p>
        ) : loadError ? (
          <div className={styles.errorBox} role="alert">
            <p>{loadError}</p>
            <button className={styles.ghost} onClick={() => loadLinks(apiKey)}>
              Try again
            </button>
          </div>
        ) : links.length === 0 ? (
          <p className={styles.muted}>
            No links yet. Shorten one above and it'll show up here.
          </p>
        ) : (
          <div className={styles.tableWrap}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Short</th>
                  <th>Destination</th>
                  <th className={styles.num}>Clicks</th>
                  <th>Created</th>
                  <th>Expires</th>
                  <th />
                </tr>
              </thead>
              <tbody>
                {links.map((link) => {
                  const expired = isExpired(link);
                  return (
                    <tr key={link.code} className={expired ? styles.dead : ""}>
                      <td>
                        <a
                          className={styles.mono}
                          href={link.short_url}
                          target="_blank"
                          rel="noreferrer"
                        >
                          /{link.code}
                        </a>
                      </td>
                      <td className={styles.dest} title={link.long_url}>
                        {link.long_url}
                      </td>
                      <td className={styles.num}>{link.click_count}</td>
                      <td className={styles.muted}>
                        {formatRelative(link.created_at)}
                      </td>
                      <td className={styles.muted}>
                        {link.expires_at
                          ? expired
                            ? "Expired"
                            : formatRelative(link.expires_at)
                          : "Never"}
                      </td>
                      <td>
                        <button
                          className={styles.copy}
                          onClick={() => copy(link.short_url)}
                        >
                          {copied === link.short_url ? "Copied" : "Copy"}
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </section>
    </main>
  );
}

