input.content:
.main {
  width: 100%;
  max-width: 62rem;
  margin: 0 auto;
  padding: 3rem 1.5rem 4rem;
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

/* --- signed-out gate ------------------------------------------------------ */

.gate {
  margin: auto;
  max-width: 26rem;
  display: flex;
  flex-direction: column;
  gap: 1rem;
  text-align: center;
}

.gateForm {
  display: flex;
  gap: 0.5rem;
}

.lede {
  color: var(--muted);
  line-height: 1.6;
  font-size: 0.9375rem;
}

.note {
  color: var(--muted);
  font-size: 0.8125rem;
  line-height: 1.5;
}

/* --- header --------------------------------------------------------------- */

.header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: 1rem;
}

.title {
  font-size: 1.75rem;
  font-weight: 650;
  letter-spacing: -0.02em;
}

.sectionTitle {
  font-size: 0.8125rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--muted);
  margin-bottom: 0.75rem;
}

/* --- form ----------------------------------------------------------------- */

.form {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.row {
  display: flex;
  gap: 0.5rem;
}

.input,
.ttl {
  flex: 1;
  padding: 0.625rem 0.75rem;
  font: inherit;
  font-size: 0.9375rem;
  color: var(--foreground);
  background: var(--background);
  border: 1px solid var(--border);
  border-radius: 8px;
  outline: none;
}

.ttl {
  flex: 0 0 9rem;
}

.input:focus,
.ttl:focus {
  border-color: var(--foreground);
}

.input::placeholder,
.ttl::placeholder {
  color: var(--muted);
}

.primary {
  padding: 0.625rem 1.125rem;
  font: inherit;
  font-size: 0.9375rem;
  font-weight: 550;
  color: var(--accent-fg);
  background: var(--accent);
  border: 1px solid var(--accent);
  border-radius: 8px;
  cursor: pointer;
  white-space: nowrap;
}

.primary:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.ghost {
  padding: 0.375rem 0.75rem;
  font: inherit;
  font-size: 0.8125rem;
  color: var(--muted);
  background: none;
  border: 1px solid var(--border);
  border-radius: 6px;
  cursor: pointer;
}

.ghost:hover {
  color: var(--foreground);
  border-color: var(--foreground);
}

/* --- result --------------------------------------------------------------- */

.result {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.875rem 1rem;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
}

.resultLink {
  font-family: var(--font-geist-mono), ui-monospace, monospace;
  font-size: 0.9375rem;
  overflow-wrap: anywhere;
}

.resultLink:hover {
  text-decoration: underline;
}

.copy {
  padding: 0.3125rem 0.625rem;
  font: inherit;
  font-size: 0.75rem;
  color: var(--muted);
  background: var(--background);
  border: 1px solid var(--border);
  border-radius: 6px;
  cursor: pointer;
  white-space: nowrap;
}

.copy:hover {
  color: var(--foreground);
  border-color: var(--foreground);
}

/* --- dashboard ------------------------------------------------------------ */

.dash {
  display: flex;
  flex-direction: column;
}

/* Tables don't reflow. Let this one scroll rather than blow out the page. */
.tableWrap {
  overflow-x: auto;
  border: 1px solid var(--border);
  border-radius: 8px;
}

.table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.875rem;
}

.table th {
  padding: 0.625rem 0.875rem;
  text-align: left;
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--muted);
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
}

.table td {
  padding: 0.75rem 0.875rem;
  border-bottom: 1px solid var(--border);
  vertical-align: middle;
}

.table tr:last-child td {
  border-bottom: none;
}

.mono {
  font-family: var(--font-geist-mono), ui-monospace, monospace;
  font-weight: 500;
}

.mono:hover {
  text-decoration: underline;
}

/* Long URLs would otherwise stretch the table past the viewport. */
.dest {
  max-width: 22rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--muted);
}

.num {
  text-align: right;
  font-variant-numeric: tabular-nums;
}

.dead {
  opacity: 0.5;
}

/* --- states --------------------------------------------------------------- */

.muted {
  color: var(--muted);
  font-size: 0.875rem;
}

.error {
  color: var(--danger);
  font-size: 0.875rem;
}

.errorBox {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.875rem 1rem;
  color: var(--danger);
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  font-size: 0.875rem;
}

.code {
  font-family: var(--font-geist-mono), ui-monospace, monospace;
  font-size: 0.8125em;
  padding: 0.1em 0.35em;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 4px;
}

@media (max-width: 40rem) {
  .row {
    flex-direction: column;
  }

  .ttl {
    flex: 1;
  }
}

