  setLoading(true);
  try {
    setLinks(await getLinks(key));
    setLoadError(null);
  } catch (e) {
    const message =
      e instanceof ApiError ? e.message : "Couldn't load your links.";
    setLoadError(message);
    // A bad key shouldn't leave a stale list on screen implying it worked.
    if (e instanceof ApiError && e.status === 401) setLinks([]);
  } finally {
    setLoading(false);
