/**
 * Fetch the calling key's links.
 *
 * `isStale` guards against a real race: switch keys while a request is in
 * flight and the slower response can land last, painting one key's links
 * under another key's session. The check drops any response whose key is no
 * longer the current one.
 */
const loadLinks = useCallback(async (key: string, isStale = () => false) => {
  setLoading(true);
  try {
    const fetched = await getLinks(key);
    if (isStale()) return;
    setLinks(fetched);
    setLoadError(null);
  } catch (e) {
    if (isStale()) return;
    setLoadError(e instanceof ApiError ? e.message : "Couldn't load your links.");
    // A rejected key shouldn't leave a stale list on screen implying it worked.
    if (e instanceof ApiError && e.status === 401) setLinks([]);
  } finally {
    if (!isStale()) setLoading(false);
  }
}, []);

useEffect(() => {
  if (!apiKey) return;
  let cancelled = false;
  loadLinks(apiKey, () => cancelled);
  return () => {
    cancelled = true;
  };
}, [apiKey, loadLinks]);

