  e.preventDefault();
  const trimmed = keyDraft.trim();
  if (!trimmed) return;
  keyStore.setApiKey(trimmed);
  setKeyDraft("");
  setLoadError(null);
}

function forgetKey() {
  keyStore.clearApiKey();
  setLinks([]);
  setJustCreated(null);
  setLoadError(null);
}

