"""Render a Claude Code session .jsonl into readable Markdown."""
import json, sys

src, dst = sys.argv[1], sys.argv[2]
out = []

def text_of(content):
    """Content is either a string or a list of typed blocks."""
    if isinstance(content, str):
        return [("text", content)]
    parts = []
    for b in content or []:
        if not isinstance(b, dict):
            continue
        t = b.get("type")
        if t == "text":
            parts.append(("text", b.get("text", "")))
        elif t == "thinking":
            parts.append(("thinking", b.get("thinking", "")))
        elif t == "tool_use":
            parts.append(("tool_use", (b.get("name"), b.get("input", {}))))
        elif t == "tool_result":
            c = b.get("content")
            if isinstance(c, list):
                c = "\n".join(x.get("text", "") for x in c if isinstance(x, dict))
            parts.append(("tool_result", c or ""))
    return parts

def clip(s, n=1600):
    s = str(s)
    return s if len(s) <= n else s[:n] + f"\n… [{len(s)-n} more chars truncated]"

for line in open(src):
    try:
        d = json.loads(line)
    except Exception:
        continue
    if d.get("type") not in ("user", "assistant"):
        continue
    msg = d.get("message") or {}
    role = msg.get("role") or d.get("type")
    for kind, payload in text_of(msg.get("content")):
        if kind == "text" and payload.strip():
            out.append(f"### {'👤 User' if role=='user' else '🤖 Claude'}\n\n{payload.strip()}\n")
        elif kind == "thinking" and payload.strip():
            out.append(f"<details><summary>💭 Claude's thinking</summary>\n\n```\n{clip(payload.strip(), 2500)}\n```\n</details>\n")
        elif kind == "tool_use":
            name, inp = payload
            arg = inp.get("command") or inp.get("file_path") or inp.get("skill") or inp.get("pattern") or ""
            body = ""
            if inp.get("content"):
                body = f"\n```\n{clip(inp['content'], 900)}\n```"
            elif inp.get("command"):
                body = f"\n```bash\n{clip(inp['command'], 900)}\n```"
            out.append(f"**🔧 {name}** `{clip(arg,120)}`{body}\n")
        elif kind == "tool_result" and str(payload).strip():
            out.append(f"<details><summary>📄 Result</summary>\n\n```\n{clip(payload, 1200)}\n```\n</details>\n")

header = """# Claude Code Session Transcript

Project B (AI-assisted) — URL Shortener.
Rendered from the raw session log at `session.jsonl`, which is the authoritative export.

Long tool outputs and thinking blocks are truncated for readability; nothing is
re-ordered or reworded. Collapsed sections expand.

---

"""
open(dst, "w").write(header + "\n".join(out))
print(f"rendered {len(out)} blocks -> {dst}")
